"""
MKT Original Commentary — Luke chapters 4–5
Run: python3 scripts/zc-original-luke-4-5.py

Source data used:
- data/interlinear/luke.json
- data/translation/draft/mediating/luke.json
- data/translation/glossary-greek.json

Key decisions in this range:
- Luke 4:1–13: Temptation follows deuteronomic pattern (Deut 6–8 citations);
  Luke omits "but by every word of God" from Deut 8:3 quote (v.4), probably
  for concision; the diabolos's departure "until an opportune time" (v.13)
  is Lukan foreshadowing of 22:3 (Satan enters Judas).
- Luke 4:16–30: Nazareth pericope placed programmatically at ministry's start
  (vs. Mark 6:1-6 later). Isa 61:1-2 + 58:6 composite quote; epistatēs
  (master/commander) is Luke's distinctive title for Jesus vs. didaskalos/rabbi.
- Luke 5:8: Peter's confession echoes Isaiah 6:5; hamartolos (sinner) is
  Lukan key term (most frequent in the Gospels).
- Lukan prayer emphasis: Jesus prays at baptism (3:21), after cleansing leper
  (5:16), before choosing the Twelve (6:12) — each major event preceded by prayer.
- egongyzon (5:30) is LXX term for wilderness murmuring; Luke signals
  the Pharisees as recapitulating Israel's sin against Moses.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

LUKE = {
  "4": {
    "1": '<p><strong>pleres pneumatos hagiou</strong> — full of the Holy Spirit — Luke adds <em>pleres</em> (full) to Mark\'s simpler account; the same adjective describes Stephen (Acts 6:5) and Barnabas (Acts 11:24), making Spirit-fullness a mark of God\'s commissioned agents. <strong>ēgeto en tō pneumati</strong> — was led by the Spirit — the passive <em>ēgeto</em> (imperfect, ongoing action) stresses that the wilderness journey is Spirit-driven, not a retreat. The <em>eremos</em> (wilderness/desert) echoes Israel\'s forty-year desert testing (Num 14:33; Deut 8:2).</p>',
    "2": '<p><strong>hemeras tesserakonta</strong> — forty days — the number recapitulates Israel\'s forty-year wilderness test (Deut 8:2) and Moses\'s forty-day fast on Sinai (Exod 34:28). <strong>peirazomenos hypo tou diabolou</strong> — being tempted by the devil — <em>diabolos</em> (slanderer, accuser) is Luke\'s preferred term (vs. <em>satanas</em> in Mk 1:13); it carries the forensic overtone of an adversarial prosecutor. The imperfect <em>peirazomenos</em> indicates ongoing pressure throughout the forty days, not just the three climactic exchanges that follow.</p>',
    "3": '<p><strong>ei huios ei tou theou</strong> — if you are the Son of God — the conditional is first class in Greek, assuming the reality of the premise; the devil does not doubt the title but uses it to direct what the Son of God should do. <strong>eipe tō lithō toutō hina genētai artos</strong> — command this stone to become bread — the test targets trust in God\'s provision; Israel complained about lack of bread in the wilderness (Exod 16:3; Num 11:4-6). The singular stone contrasts with Matthew\'s plural "these stones" (Mt 4:3), focusing the personal challenge.</p>',
    "4": '<p><strong>gegraptai hoti ouk ep artō monō zesetai ho anthrōpos</strong> — it is written: man shall not live on bread alone — Jesus cites Deut 8:3 from memory, the passage about YHWH\'s provision of manna and the purpose of the forty-year desert: to teach Israel to trust God\'s word over physical appetite. Luke\'s version omits Matthew\'s continuation ("but by every word that comes from the mouth of God"), keeping the focus on the sufficiency of the written word as a counter to the devil\'s premise. <em>Gegraptai</em> (it is written, perfect passive) frames scripture as settled, authoritative, and present-tense binding.</p>',
    "5": '<p><strong>anagagōn auton edeixen autō pasas tas basileias tēs oikoumenēs</strong> — leading him up, he showed him all the kingdoms of the inhabited world — <em>oikoumenē</em> (the inhabited world, the Roman empire\'s self-description) implies political totality; Luke\'s version omits the specific "very high mountain" of Matthew. The display is instantaneous (<em>en stigmē chronou</em> = in a moment of time), suggesting visionary or supernatural perception rather than geographic vantage. Luke places this temptation second (Matthew places it third), centering the political-power temptation before the temple-leap.</p>',
    "6": '<p><strong>soi dōsō tēn exousian tautēn hapasan kai tēn doxan autōn, hoti emoi paradedotai</strong> — I will give you all this authority and their glory, because it has been handed over to me — the devil claims delegated authority over the kingdoms: <em>paradedotai</em> (perfect passive, has been handed over) implies YHWH\'s permission, not self-seizure. This theological datum appears only in Luke; it frames earthly political power as operating within a sphere the devil administers — a sobering commentary on the nature of worldly authority. <em>Exousia</em> (authority) and <em>doxa</em> (glory) are the two components of what Gentile rulers pursued; the devil offers both.</p>',
    "7": '<p><strong>sy oun ean proskunēsēs enōpion emou, estai sou pasa</strong> — if therefore you worship before me, it will all be yours — <em>proskuneō</em> (worship, do obeisance, prostrate) is the term used for proper worship of YHWH and of Jesus in Luke-Acts; the devil demands the same posture. The offer short-circuits the cross: all authority without suffering. The irony Luke\'s audience perceives: Jesus will receive all authority (Mt 28:18; Acts 1:8) — but through death and resurrection, not demonic bargain.</p>',
    "8": '<p><strong>gegraptai, Kyrion ton theon sou proskunēseis kai autō monō latreuseis</strong> — it is written: you will worship the Lord your God, and him only will you serve — Deut 6:13 (LXX), from the Shema context (Deut 6:4-15). <em>Latreuseis</em> (you will serve, do cultic service) is the term for Levitical temple service; exclusive liturgical devotion to YHWH is the counterpart to exclusive political authority offered by the devil. The citation repudiates the offer by grounding authority in worship rather than negotiation.</p>',
    "9": '<p><strong>hēgagen de auton eis Ierousalem kai estēsen epi to pterygion tou hierou</strong> — he led him to Jerusalem and set him on the pinnacle of the temple — Luke\'s final temptation is in Jerusalem, not in Galilee (reversing Matthew\'s order), which serves Luke\'s theological geography: Jerusalem is the climax of every movement in his narrative (the Gospel ends with the disciples remaining in Jerusalem; Acts begins there). <em>Pterygion tou hierou</em> (pinnacle of the temple) likely refers to the southeast corner of Herod\'s temple complex where the Royal Stoa met the Kidron Valley far below.</p>',
    "10": '<p><strong>tois angelois autou enteleistai peri sou tou diaphylaxai se</strong> — he will command his angels concerning you to guard you — Ps 91:11-12 quoted by the devil as the basis for a trust-test: if Jesus is the Son of God, God\'s own promise guarantees protection from fall. The irony is that Ps 91 is a wisdom psalm about the one who trusts YHWH in genuine danger; the devil weaponizes it to encourage manufactured danger. The text of the citation is verbatim LXX except for the omission of "in all your ways" (Ps 91:11b).</p>',
    "11": '<p><strong>kai hoti epi cheirōn arousin se, mēpote proskopsēs pros lithon ton poda sou</strong> — and they will lift you up on their hands, so that you will not strike your foot against a stone — Ps 91:12, completing the citation. The imagery is angelic protection: divine messengers sustaining the trusting one from stumbling. The devil\'s inversion: what the psalm celebrates as God\'s care for the endangered believer is here reframed as justification for self-induced catastrophe. Deliberate misreading of scripture is the third temptation\'s method.</p>',
    "12": '<p><strong>kai apokritheis eipen autō ho Iēsous hoti eirētai, Ouk ekpeiraseis Kyrion ton theon sou</strong> — Jesus answered and said to him: it is said, you shall not put the Lord your God to the test — Deut 6:16 (LXX), citing Israel\'s testing of YHWH at Massah/Meribah (Exod 17:1-7) where they demanded miraculous water as proof of God\'s presence. <em>Ekpeiraseis</em> (you will test, put to the test) is the compound form of <em>peirazō</em>, intensified by the prefix. Jesus refuses to weaponize God\'s faithfulness as a safety-net for manufactured crises.</p>',
    "13": '<p><strong>kai syntelesas panta peirasmon ho diabolos apestē ap autou achri kairou</strong> — having completed every temptation, the devil departed from him until an opportune time — <em>syntelesas panta peirasmon</em> (having finished all the temptation) — Luke\'s phrase implies these three exchanges were representative of a comprehensive testing, not exhaustive in themselves. <em>Achri kairou</em> (until an opportune time, an appointed moment) is Lukan foreshadowing: in 22:3 Satan enters Judas and the Passion begins. The wilderness conflict is temporarily suspended, not resolved; the cross will be the decisive engagement.</p>',
    "14": '<p><strong>kai hypestrepsen ho Iēsous en tē dynamei tou pneumatos eis tēn Galilaian</strong> — Jesus returned to Galilee in the power of the Spirit — <em>dynamis</em> (power) is Luke\'s key word for the Spirit\'s operative force (cf. 1:35; Acts 1:8; 10:38). The Spirit who led Jesus into the wilderness now empowers his Galilean ministry; the forty-day testing produced not defeat but intensified spiritual authority. <strong>phēmē exēlthen kath holēs tēs perichōrou</strong> — news went out through the whole surrounding countryside — <em>phēmē</em> (reputation, fame) spreads from first-hand witness before Jesus himself explains anything.</p>',
    "15": '<p><strong>kai autos edidasken en tais synagōgais autōn doxazomenos hypo pantōn</strong> — and he was teaching in their synagogues, being glorified by all — the imperfect <em>edidasken</em> (was teaching) indicates repeated synagogue teaching across multiple towns; <em>doxazomenos</em> (being glorified, praised) reflects the audience\'s positive initial reception before the Nazareth controversy. The synagogue circuit (cf. Mt 4:23; Mk 1:39) is Jesus\'s primary early platform: public reading and exposition of Torah within the covenant community.</p>',
    "16": '<p><strong>kai ēlthen eis Nazara, hou ēn tethrammenos</strong> — he came to Nazareth, where he had been brought up — <em>tethrammenos</em> (perfect passive participle of <em>trephō</em>, to nurture, raise) emphasizes Nazareth as the site of Jesus\'s formation, not just his birthplace. Luke places this synagogue scene at the opening of the Galilean ministry (vs. Mark 6:1-6, which places it after many miracles); it functions as the programmatic statement of Jesus\'s mission before it plays out. <strong>kata to eiōthos autō</strong> — as was his custom — Jesus\'s synagogue attendance is habitual, not occasional; he is a Torah-observant Jew.</p>',
    "17": '<p><strong>kai epedothē autō biblion tou prophētou Ēsaiou</strong> — the scroll of the prophet Isaiah was handed to him — the <em>biblion</em> (scroll, book) was the Isaiah scroll of the synagogue. The attendant (<em>hyperetēs</em>) would hand the scroll to the reader; the reader would stand to read and sit to expound. Luke notes that Jesus <em>unrolled</em> it (<em>anaptuxas</em>, unrolled/opened) and <em>found</em> (<em>heuren</em>) the place — a deliberate search, not random selection. The passage is Isa 61:1-2 with an insertion from Isa 58:6 ("to set the oppressed free").</p>',
    "19": '<p><strong>kēruxai eniauton Kyriou dekton</strong> — to proclaim the year of the Lord\'s favor — the Jubilee year (Lev 25:8-55) is the economic-social institution in which debts are cancelled, slaves freed, and alienated land restored. Jesus does not announce a calendar Jubilee but the eschatological reality the Jubilee pointed toward: the age of God\'s acceptance and restorative mercy. <em>Dekton</em> (acceptable, favored, welcomed) is the quality of the era; Luke\'s theology of time presents this as <em>semeron</em> (today, v.21) — the present moment of proclamation is the era of favor.</p>',
    "20": '<p><strong>ptuxas to biblion apodous tō hyperetē ekathisen</strong> — rolling up the scroll and giving it back to the attendant, he sat down — the seated posture was the authoritative teaching position for rabbis and synagogue teachers (cf. Mt 5:1; 23:2; Lk 5:3); standing was for public reading. The transition from standing reader to seated teacher signals that exposition is about to begin. <strong>kai pantōn hoi ophthalmoi en tē synagōgē ēsan atenizovtes autō</strong> — the eyes of all in the synagogue were fixed on him — <em>atenizō</em> (to fix one\'s eyes on, gaze intently) is a Lukan word for concentrated attention (Acts 1:10; 3:4; 6:15).</p>',
    "22": '<p><strong>kai pantes emartyroyn autō kai ethaumazon epi tois logois tēs charitos</strong> — all bore witness to him and were amazed at the gracious words coming from his mouth — <em>hoi logoi tēs charitos</em> (the words of grace/gift) is unusual; it may mean words of gracious content (announcing favor) or words spoken with charis (rhetorical grace). The initial reception is positive — amazement — before the challenge. <strong>ouchi huios estin Iōsēph houtos</strong> — is this not Joseph\'s son? — the rhetorical question marks the audience\'s frame for Jesus: a hometown craftsman\'s son whose social standing is known. The question is incredulous, not hostile yet.</p>',
    "23": '<p><strong>pantōs ereite moi tēn parabolēn tautēn, Iatre, therapeusen seauton</strong> — surely you will say to me this proverb: Physician, heal yourself — Jesus anticipates the Nazareth crowd\'s demand with a proverb known from Greek and Semitic sources (cf. b. Sanhedrin 17a). The implicit challenge: demonstrate at home what you have done elsewhere. <strong>Hosa ēkousamen genomena eis tēn Kapharnaoum, poiēson kai hōde</strong> — whatever we heard happened in Capernaum, do also here — the Nazareth audience has heard about Capernaum miracles (though Luke has not yet narrated them); the hometown crowd expects privileged access to divine power.</p>',
    "24": '<p><strong>oudeis prophētēs dektos estin en tē patridi autou</strong> — no prophet is accepted in his hometown — <em>dektos</em> (acceptable, welcome) echoes v.19 ("the year of the Lord\'s <em>favor/acceptance</em>"); the Jubilee-favor pronounced on the poor is withheld from the prophet by his own town. This is not a proverb Jesus merely cites but a pattern he identifies as programmatic for his own ministry; prophets from Moses to Elijah faced rejection from Israel. Luke\'s <em>amēn legō hymin</em> (truly I tell you) marks the saying as solemn declaration.</p>',
    "25": '<p><strong>pollai chērai ēsan en tais hēmerais Ēliou</strong> — there were many widows in Israel in the days of Elijah — Jesus cites 1 Kgs 17-18 to make the scandalous point that divine mercy bypassed the covenant people and went to a Gentile. The three-and-a-half-year drought (cf. Jas 5:17) created mass famine. <em>Chērai</em> (widows) are the paradigmatic vulnerable poor of the OT; their plight during the drought was Israel\'s judgment situation, yet Elijah was sent to none of them.</p>',
    "26": '<p><strong>all epi Sarepta tēs Sidōnias pros gynaika chēran</strong> — but to Zarephath of Sidon, to a widow woman — <em>Sarepta</em> is in Phoenician territory, outside Israel\'s borders; the widow there is a Gentile. This is not a minor detail: YHWH deliberately bypassed the many needy Israelite widows and directed Elijah to a foreign woman. Luke uses this OT precedent to legitimize Jesus\'s ministry reaching beyond ethnic Israel — a theme that will climax in Acts. The pattern offends Nazareth precisely because it decentralizes covenant privilege.</p>',
    "27": '<p><strong>kai polloi leproi ēsan epi Elisaiou tou prophētou en tō Israēl</strong> — and there were many lepers in Israel in the time of the prophet Elisha — 2 Kgs 5 is the parallel case: Naaman the Syrian (Aramean) general, not an Israelite, was the one cleansed. <em>Oudeois autōn ekatharisthē ei mē Naiman ho Syros</em> — none of them was cleansed except Naaman the Syrian. The point is double: divine healing power was available during Elisha\'s era, but it went to a Gentile military officer. The Nazareth crowd\'s fury (v.28) is the direct consequence of this implication for Jesus\'s ministry.</p>',
    "28": '<p><strong>eplesthesan pantes thymon en tē synagōgē</strong> — all in the synagogue were filled with rage — <em>thymos</em> (wrath, rage, passionate anger) contrasts with the initial <em>thaumazein</em> (amazement) of v.22; the congregation moved from wonder to murderous fury in moments. The trigger was not an insult to their religion but the implication that God\'s eschatological favor might pass over Israel in favor of Gentiles — the scandal of divine election working beyond ethnic boundaries. Their fury is the first enactment of the rejection-of-the-prophet pattern Jesus just announced.</p>',
    "29": '<p><strong>kai anastantes exebalon auton exō tēs poleōs kai ēgagon auton heōs ophryos tou orous</strong> — rising up, they drove him out of the city and led him to the brow of the hill on which the city was built — mob action: the congregation becomes a mob and drives Jesus from the synagogue, out of town, and to a cliff. <em>Ophrys</em> (brow, ridge, eyebrow) refers to the hill\'s edge above a precipice. <em>Katakremnisai auton</em> (to throw him down) was the method of summary execution by cliff-throwing used in Israel\'s antiquity (cf. 2 Chr 25:12); they intend to kill him.</p>',
    "30": '<p><strong>autos de dielthōn dia mesou autōn eporeueto</strong> — but he passed through the middle of them and went on his way — the escape is narrated without explanation of method: no angelic intervention, no miraculous blindness is mentioned. The point is simply that Jesus departed; Luke\'s reticence is more impressive than Matthew\'s or John\'s (cf. Jn 8:59; 10:39). His hour has not come (cf. Jn 7:30); the first attempt to kill him fails because the appointed time has not arrived. He "went on his way" (<em>eporeueto</em> imperfect = continued traveling) — the mission continues undeterred.</p>',
    "31": '<p><strong>kai katēlthen eis Kapharnaoum polin tēs Galilaias</strong> — he went down to Capernaum, a city of Galilee — <em>katēlthen</em> (went down) reflects geography: Nazareth is at 370m elevation; Capernaum is on the north shore of the Sea of Galilee at -210m. Capernaum becomes Jesus\'s Galilean base (cf. 4:23, where the Nazarenes anticipated this). Luke adds "a city of Galilee" — a Gentile reader\'s orientation note. <strong>kai ēn didaskōn autous en tois sabbasin</strong> — and he was teaching them on the Sabbaths — the imperfect indicates regular weekly synagogue teaching.</p>',
    "32": '<p><strong>kai exeplēssonto epi tē didachē autou, hoti en exousia ēn ho logos autou</strong> — they were astonished at his teaching, because his word was with authority — <em>exeplēssonto</em> (were astonished, struck out of their senses) is a strong reaction verb. <em>Exousia</em> (authority) is the theological key: rabbis taught by citation of predecessors ("Rabbi X says..."); Jesus taught with direct pronouncement. His word carries its own authorization without appeal to tradition. Luke pairs <em>exousia</em> (authority) with <em>dynamis</em> (power) in v.36 — the conceptual twins of his ministry.</p>',
    "33": '<p><strong>kai en tē synagōgē ēn anthrōpos echōn pneuma daimoniou akathartou</strong> — in the synagogue there was a man having a spirit of an unclean demon — the demon\'s presence in the synagogue is deliberate: the first confrontation occurs in the house of worship, not in the streets. <em>Pneuma daimoniou akathartou</em> is Luke\'s compound phrase combining <em>daimonion</em> (demon, divine being) and <em>akathartos</em> (unclean, ritually impure). The man\'s possession disrupts the covenant assembly. <strong>kai anekraxen phōnē megalē</strong> — and he cried out with a loud voice — the demon\'s involuntary confrontation of Jesus.</p>',
    "34": '<p><strong>Ea, ti hēmin kai soi, Iēsou Nazarēne</strong> — Let us alone! What have you to do with us, Jesus of Nazareth? — <em>Ea</em> is an interjection of protest or alarm. <em>Ti hēmin kai soi</em> (what to us and to you? = what do we have to do with each other?) is a Semitic idiom of non-engagement (cf. Judg 11:12; 2 Sam 16:10). The demon identifies Jesus geographically (<em>Nazarēne</em>) and with full theological precision: <strong>ho hagios tou theou</strong> — the Holy One of God — a unique Christological title combining holiness (consecrated, set apart) with divine origin. Demonic knowledge precedes human confession.</p>',
    "35": '<p><strong>kai epitimēsen autō ho Iēsous legōn, Phimōthēti kai exelthe ap autou</strong> — Jesus rebuked him saying: Be muzzled and come out of him — <em>epitimēsen</em> (rebuked, charged sternly) is Luke\'s standard verb for Jesus\'s authoritative command over demons and natural forces (cf. 8:24 wind and waves; 4:39 fever). <em>Phimōthēti</em> (be silenced, be muzzled) suppresses both the demon\'s speech and its further activity. <strong>mēden blapsas auton</strong> — having harmed him in nothing — Luke\'s medical observation (cf. Mk 1:26 where convulsion and a loud cry are noted); Luke emphasizes the clean, harmless exit as evidence of complete divine control.</p>',
    "36": '<p><strong>kai egeneto thambos epi pantas</strong> — astonishment came upon all — <em>thambos</em> (astonishment, wonder mixed with fear) is the reaction to the unprecedented. They interpret what they witnessed: <strong>hoti en exousia kai dynamei epitassei tois akathartois pneumasin</strong> — because with authority and power he commands the unclean spirits, and they come out. <em>Exousia kai dynamis</em> — authority and power — are Luke\'s paired theological concepts: <em>exousia</em> is the right to command; <em>dynamis</em> is the effective force executing the command. Both characterize Jesus\'s ministry throughout Luke-Acts.</p>',
    "37": '<p><strong>kai exeporeueto ēchos peri autou eis panta topon tēs perichōrou</strong> — and a report about him went out to every place in the surrounding region — <em>ēchos</em> (echo, sound, report — Luke\'s medical vocabulary extended metaphorically) marks the spread of reputation without formal announcement. <em>Perichōros</em> (surrounding region) implies the countryside around Capernaum, including the Jordan Valley settlements. News of exorcisms by word alone was extraordinary; Jewish exorcism practices of the period involved elaborate rituals and incantations (cf. Josephus, Ant. 8.46-48).</p>',
    "38": '<p><strong>anastas de apo tēs synagōgēs eisēlthen eis tēn oikian Simōnos</strong> — rising from the synagogue he entered Simon\'s house — the sequence is direct: synagogue → Simon\'s house in Capernaum. This is the first mention of Simon Peter\'s home in Luke (though Mk 1:29-31 introduces Simon earlier). <strong>penthera de tou Simōnos ēn synechomenē pyretō megalō</strong> — Simon\'s mother-in-law was being held by a great fever — <em>synekhomenē</em> (was being held, constrained, pressed) is a medical term; Luke adds <em>megalō</em> (great/high) to describe the fever\'s severity, consistent with Luke\'s medical vocabulary (<em>pyretō megalō</em> corresponds to what ancient physicians called a dangerous systemic fever).</p>',
    "39": '<p><strong>kai epistas epanō autēs epetimēsen tō pyretō</strong> — standing over her, he rebuked the fever — the same verb <em>epitimēsen</em> used against the demon (v.35) is here applied to a fever — an unprecedented usage that treats disease as something subject to command and rebuke, not merely to medical treatment. Jesus does not administer medicine or pray; he commands the fever directly. <strong>kai aphēken autēn</strong> — and it left her — the fever\'s departure is described with the same verb (<em>aphiēmi</em>) used for the departure of demons; Luke treats the healing as a liberation. <strong>parachrēma de anastasa diēkonei autois</strong> — immediately she rose and was serving them — instant and complete restoration.</p>',
    "40": '<p><strong>dynontos de tou hēliou hapantes hosoi eichon asthenountas nosois poikilais ēgagon autous pros auton</strong> — as the sun was setting, all who had sick people with various diseases brought them to him — the Sabbath ended at sunset; carrying the sick was prohibited on the Sabbath (m. Shabb. 10:5), so the crowd waited until sunset before bringing the ill. The mass healing session is Lukan: <strong>ho de heni hekastō autōn tas cheiras epititheis etherapeuev autous</strong> — laying his hands on each one of them, he healed them — Luke\'s individual attention: not a collective healing wave but personal <em>laying on of hands</em> (<em>cheiras epititheis</em>) on each person, the apostolic gesture of conferring blessing and healing.</p>',
    "41": '<p><strong>exērcheto de kai daimonia apo pollōn krazonta kai legonta hoti sy ei ho huios tou theou</strong> — demons were coming out of many, crying and saying: you are the Son of God — the collective demonic confession of Jesus\'s divine sonship (cf. v.34 "the Holy One of God") is the involuntary testimony of the spirit world to what the human world has not yet recognized. <strong>kai epitimōn ouk eia auta lalein, hoti ēdeisan ton Christon auton einai</strong> — rebuking them, he would not allow them to speak, because they knew him to be the Christ — the messianic secret: Jesus silences demonic identification of his identity. The reason Luke gives is theological: their knowledge of his Messianic role (not just his divine sonship) is what must not be premature announced.</p>',
    "42": '<p><strong>genomenēs de hēmeras exelthōn eporeuthe eis erēmon topon</strong> — when day came, he went out and went to a solitary place — Luke\'s characteristic emphasis on Jesus at prayer: this verse in Luke becomes an explicit prayer scene in the parallel account\'s pattern (cf. 5:16; 6:12; 9:18; 11:1; 22:41). The withdrawal to <em>erēmos topos</em> (deserted/solitary place) after a full day of healing and exorcism follows the pattern of Moses and Elijah in wilderness retreat. <strong>hoi de ochloi epezētoun auton</strong> — the crowds were seeking him — <em>epizēteō</em> (seek eagerly, search for) indicates pressing need; they tried to prevent him from departing.</p>',
    "43": '<p><strong>ho de eipen pros autous hoti kai tais hetrais polesin euangelisasthai me dei tēn basileian tou theou</strong> — he said to them: I must proclaim the good news of the kingdom of God to the other towns also — <em>dei</em> (it is necessary, I must) is Luke\'s divine-compulsion word, marking what God has appointed and what Jesus cannot deviate from (cf. 2:49; 9:22; 13:33; 24:26,44). <em>Euangelisasthai</em> (to proclaim good news) is Luke\'s preferred verb for Jesus\'s mission; it occurs more in Luke-Acts than in all other NT books combined. <strong>hoti epi touto apestalmēn</strong> — because for this I was sent — the mission statement in brief: apostolic sending by the Father to proclaim the kingdom.</p>',
    "44": '<p><strong>kai ēn kēryssōn eis tas synagōgas tēs Ioudaias</strong> — and he was preaching in the synagogues of Judea — <em>Ioudaias</em> here likely means the broader Jewish region (cf. 1:5 where "Judea" encompasses the whole land), not the southern province exclusively, since the preceding narrative is in Galilee. Luke uses <em>kēryssōn</em> (preaching, proclaiming as a herald) as a summary-verb for the Galilean circuit, distinguishing it from the more content-specific <em>euangelizesthai</em> (v.43). The imperfect tense continues the panoramic summary of the mission\'s scope.</p>',
  },
  "5": {
    "1": '<p><strong>egeneto de en tō ton ochlon epikesthai autō kai akouein ton logon tou theou</strong> — as the crowd was pressing upon him and hearing the word of God — <em>epikeimai</em> (to press upon, lie on) describes the physical pressure of an eager crowd. Luke identifies Jesus\'s teaching as <em>ton logon tou theou</em> (the word of God), not merely rabbinic instruction; this identification is programmatic in Luke-Acts where the apostolic message is consistently called <em>ho logos tou theou</em> (Acts 6:7; 12:24; 13:7). <strong>limné Gennésaret</strong> — the Lake of Gennesaret — Luke\'s preferred name for the Sea of Galilee, derived from the fertile plain on its northwest shore.</p>',
    "2": '<p><strong>kai eiden ploion dyo hestōta para tēn limnēn</strong> — he saw two boats standing by the lake — the fishermen (<em>halieis</em>) had come in after a night\'s fruitless fishing and were washing their nets (<em>eplynon ta diktya</em>) — daytime net-cleaning after the night-fishing failure Luke has established in advance of the miraculous catch narrative. The detail of net-washing indicates the end of the working night, not the beginning; the fishermen are finished and available.</p>',
    "3": '<p><strong>embas de eis hen tōn ploiōn, ho ēn Simōnos</strong> — stepping into one of the boats, the one belonging to Simon — Jesus requisitions Simon\'s boat as a teaching platform before the miraculous catch. The boat-as-pulpit (<em>ekathisen ... edidasken</em> = sitting, he was teaching) follows the seated-teacher pattern (cf. 4:20); the lake amplifies the voice for the crowd on the shore. Luke establishes the relationship between Simon and Jesus (the boat-sharing) before the call narrative of v.10-11, making the call the natural consequence of a relationship already begun rather than an abrupt summons to a stranger.</p>',
    "4": '<p><strong>hōs de epausato lalōn, eipen pros ton Simōna</strong> — when he stopped speaking, he said to Simon — the teaching ends and the testing begins. <strong>Epanagage eis to bathos kai chalasate ta diktya hymōn eis agran</strong> — put out into the deep and let down your nets for a catch — <em>bathos</em> (depth, deep water) is where fish cannot be seen from shore; the daylight instruction contradicts fishing practice (Galilean fishermen fished at night in shallow water with torchlight to attract fish). The command makes no pragmatic sense and is obeyed as an act of trust.</p>',
    "5": '<p><strong>kai apokritheis Simōn eipen, Epistata, di holēs nyktos kopiasantes ouden elabomen</strong> — Simon answered: Master, working hard all night we caught nothing — <em>Epistata</em> (master, commander, overseer) is Luke\'s exclusive title for Jesus in this pre-discipleship scene; it is not <em>rabbi</em> (teacher) or <em>kurios</em> (Lord) but the word for a military or civil commander. The professional fisherman acknowledges the night\'s failure with full honesty. <strong>epi de tō rhēmati sou chalasō ta diktya</strong> — but upon your word I will let down the nets — the transition from objection to obedience: not upon pragmatic expectation but upon <em>rhēma</em> (your specific word, command). This is the faith-response that occasions the miracle.</p>',
    "6": '<p><strong>kai touto poiēsantes synekleisan plēthos ichthyōn poly</strong> — doing this, they enclosed a great multitude of fish — <em>synekleisan</em> (enclosed, caught in a net) indicates surrounding the school from below; the verb is also used in Ezek 47:10 LXX (fishermen with nets on the shores of the restored land). <strong>dierrhēgnuto de ta diktya autōn</strong> — and their nets were breaking — the miraculous abundance strains the tools of the trade; the provision exceeds the capacity of the instruments. The net-breaking signals the completeness of the miracle rather than a mundane good catch.</p>',
    "7": '<p><strong>kai kateneusan tois metochois en tō heterō ploiō tou elthontas syllabesthai autois</strong> — they signalled to their partners in the other boat to come and help them — <em>kataneuō</em> (to signal by nodding or gesturing) implies they cannot shout over the noise or the distance; the partners in the other boat are summoned by gesture. <em>Metochoi</em> (partners, sharers) indicates a fishing cooperative; James and John are identified as partners (<em>koinōnoi</em>, v.10) of Simon. <strong>kai ēlthon kai eplēsan amphotera ta ploia, hōste bythizesthai auta</strong> — they came and filled both boats so full they were sinking — <em>bytizō</em> (to sink, submerge) dramatizes the scale; two full boats sinking under fish is the visual of abundance beyond capacity.</p>',
    "8": '<p><strong>idōn de Simōn Petros prosepesen tois gonasin Iēsou legōn, Exelthe ap emou, hoti anēr hamartolos eimi, Kyrie</strong> — when Simon Peter saw, he fell before Jesus\'s knees saying: Depart from me, for I am a sinful man, Lord — <em>prosepesen tois gonasin</em> (fell at the knees) is the posture of supplication or prostration before the holy. The response echoes Isaiah\'s throne-room vision: "Woe to me, for I am undone! I am a man of unclean lips" (Isa 6:5) — the encounter with the holy produces consciousness of sin, not just wonder. <em>Hamartolos</em> (sinner) is Luke\'s most frequent characterization of those who need salvation (5:30,32; 7:34,37,39; 15:1,2,7,10; 18:13; 19:7); it is a self-designation in the presence of recognized holiness.</p>',
    "9": '<p><strong>thambos gar perieschev auton kai pantas tous syn autō</strong> — for astonishment had seized him and all those who were with him — <em>thambos</em> (astonishment, awe) is the reaction to the numinous, the presence of power beyond human category. The same word is used in 4:36 after the exorcism; here it follows a miracle of provision. The astonishment is specifically connected to the catch: <em>epi tē agra tōn ichthyōn hōn synelabon</em> — at the catch of fish which they had taken together. The eyewitness testimony of overwhelm is Luke\'s authentication device throughout the Gospel.</p>',
    "10": '<p><strong>homoiōs de kai Iakōbon kai Iōannēn, huious Zebedaiou, hoi ēsan koinōnoi tō Simōni</strong> — similarly also James and John, sons of Zebedee, who were partners with Simon — <em>koinōnoi</em> (partners, associates in a business venture) is a commercial term; the apostolic nucleus is a family fishing business. <strong>kai eipen pros ton Simōna ho Iēsous, Mē phobou</strong> — Jesus said to Simon: Do not be afraid — the comfort-phrase in the presence of the numinous, identical to the angel\'s words to Zechariah (1:13), to Mary (1:30), and to the shepherds (2:10). <strong>apo tou nyn anthrōpous esē zōgrōn</strong> — from now on you will be catching people alive — <em>zōgreō</em> (to catch alive, take captive alive — a hunting/fishing term) transforms the vocational metaphor: fish caught die; people "caught" by proclamation gain life.</p>',
    "11": '<p><strong>kai katagagontes ta ploia epi tēn gēn, aphentes panta, ēkolouthēsan autō</strong> — pulling the boats onto the land, leaving everything, they followed him — the response to the call is total abandonment: <em>aphentes panta</em> (having left all things). Luke uses the same phrase at Levi\'s call (5:28) and later generalizes it (18:28 Peter\'s claim, 18:29 Jesus\'s promise). The two boats full of fish — a windfall catch worth a season\'s income — are left on the shore. This is Luke\'s discipleship definition at its starkest: the net full of fish abandoned with the nets.</p>',
    "12": '<p><strong>kai egeneto en tō einai auton en mia tōn poleōn kai idou anēr plērēs lepras</strong> — as he was in one of the cities, a man full of leprosy — <em>plērēs lepras</em> (full of leprosy) — Luke\'s medical term: the disease is at an advanced, total stage. <em>Lepra</em> in the NT encompasses a range of skin conditions classified under Levitical law (Lev 13-14), not only modern Hansen\'s disease. The man is ritually excluded from community (Lev 13:45-46) and approaches Jesus in violation of social protocol. <strong>pesōn epi prosōpon edeēthē autou</strong> — falling on his face, he begged him — <em>deeomai</em> (to beg, implore) is the prayer-verb; the leper approaches Jesus as a suppliant approaching God.</p>',
    "13": '<p><strong>kai ekteinas tēn cheira hēpsato autou legōn, Thelō, katharisthēti</strong> — extending his hand, he touched him saying: I am willing; be cleansed — the touch is the scandal: Jesus could have healed by word alone (cf. 4:35,39) but chooses to touch the ritually impure. Under Levitical law, touching a <em>metzora</em> (one with a skin disease) transmitted impurity (Lev 5:3); Jesus does not become impure but transfers purity. <em>Thelō</em> (I am willing) answers the leper\'s implicit doubt ("if you are willing," v.12); divine will aligns with human need. <strong>kai eutheōs hē lepra apēlthen ap autou</strong> — and immediately the leprosy departed from him — <em>apēlthen</em> (went away, departed) — the same verb for demon-departure.</p>',
    "14": '<p><strong>kai autos parēggeilen autō mēdeni eipein</strong> — he commanded him to tell no one — the messianic silence command (cf. 4:41); the proclamation of identity through miracles is premature. <strong>alla apelthōn deixon seautō tō hierai</strong> — but going, show yourself to the priest — Lev 14 prescribed a detailed seven-day purification ritual for the restored leper: the priest examined the healed person, performed two-bird sacrifice, and pronounced cleanness. The instruction to comply with the Mosaic ritual demonstrates Jesus\'s affirmation of Torah even as he transcends its mechanisms. <strong>kai prospheron peri tou katharismou sou kathōs prosetaxen Mōysēs</strong> — and offer the things concerning your cleansing as Moses commanded — the restored leper rejoins the covenant community through its own prescribed means.</p>',
    "15": '<p><strong>diērcheto de mallon ho logos peri autou</strong> — the word about him spread all the more — the Lukan irony: silence was commanded (v.14) but news spread further. <em>Ho logos</em> (the word, the report) is Luke\'s ambiguous term — it will become the technical term for the apostolic gospel proclamation in Acts. <strong>kai synērchonto ochloi polloi akouein kai therapeuesthai apo tōn astheneiōn autōn</strong> — crowds came together to hear and to be healed from their infirmities — the dual purpose of the crowds is Lukan: they come both to <em>hear</em> (the word) and to <em>be healed</em> (physical restoration). Luke consistently pairs proclamation and healing as twin dimensions of the kingdom\'s arrival.</p>',
    "16": '<p><strong>autos de ēn hypochōrōn en tais erēmois kai proseuchomenos</strong> — but he was withdrawing in the deserted places and praying — Luke\'s characteristic prayer note: this is the third Lukan mention of Jesus withdrawing to pray (cf. 3:21 at baptism; 4:42 after the Capernaum healings), and will continue at every major turning point (6:12; 9:18,28-29; 11:1; 22:41-44). <em>Hypochōreō</em> (to withdraw, retire) is stronger than Mark\'s <em>aperchomai</em>; the imperfect <em>ēn ... proseuchomenos</em> (was regularly praying) indicates a pattern, not a single occasion. Luke presents prayer as the foundation of Jesus\'s ministry, not an interruption to it.</p>',
    "17": '<p><strong>kai egeneto en mia tōn hēmerōn kai autos ēn didaskōn</strong> — one day as he was teaching — the scene is set: Jesus is teaching in a house. <strong>kai ēsan kathēmenoi Pharisaioi kai nomodidaskaloi hoi ēsan elēlythotes ek pasēs kōmēs tēs Galilaias kai Ioudaias kai Ierousalēm</strong> — Pharisees and teachers of the law were sitting, who had come from every village of Galilee, Judea, and Jerusalem — Luke stresses the representative gathering of all three regions: Galilee (north), Judea (south), and Jerusalem (the capital). This is a formal investigative delegation, not a chance encounter. <strong>kai dynamis Kyriou ēn eis to iasthai auton</strong> — and the power of the Lord was present for him to heal — Luke notes the Spirit\'s presence as the enabling condition for the miracle that follows.</p>',
    "18": '<p><strong>kai idou andres pherontes epi klinēs anthrōpon hos ēn paralalymenos</strong> — men were bringing a paralysed man on a stretcher — <em>klinē</em> is a bed or stretcher; Luke\'s version (vs. Mark\'s <em>krabatton</em>, a pallet) uses slightly more polished Greek vocabulary. <em>Paralalymenos</em> (perfect passive participle of <em>paralyō</em>, to loose at the side — a medical term for limb paralysis) is Luke\'s medical vocabulary. The four bearers (Mark 2:3 specifies four; Luke does not count them) could not access Jesus because of the crowd; the house is packed.</p>',
    "19": '<p><strong>kai mē heurontes poias eisenengkōsin auton dia ton ochlon, anabantes epi to dōma</strong> — not finding a way to bring him in through the crowd, going up onto the roof — <em>dōma</em> (flat roof, housetop) is the standard Palestinian roof accessible by exterior stairs. Luke\'s version describes removing roof tiles (<em>dia tōn keramōn</em>, through the tiles — a Hellenistic construction detail vs. Mark\'s digging through earth and thatch), reflecting an audience familiar with tiled roofs rather than Palestinian mud construction. <strong>kathēkan auton syn tō klinidiō eis to meson emprosthen tou Iēsou</strong> — they lowered him with the small stretcher into the middle in front of Jesus — the centering detail: right before Jesus, unavoidable.</p>',
    "20": '<p><strong>kai idōn tēn pistin autōn eipen, Anthrōpe, apheontai soi hai hamartiai sou</strong> — seeing their faith, he said: Friend, your sins are forgiven — <em>tēn pistin autōn</em> (their faith) encompasses both the paralyzed man and his bearers; faith visible in action (the creative roof-entry) is what Jesus perceives. <em>Anthrōpe</em> (man, friend) is a direct but not demeaning address. The forgiveness precedes the healing — Luke\'s ordering makes the theological point: forgiveness is the primary need; physical restoration follows as its sign. <em>Apheontai</em> (have been forgiven, perfect passive) declares completed forgiveness in the divine passive.</p>',
    "21": '<p><strong>kai ērxanto dialogizesthai hoi grammateis kai hoi Pharisaioi legontes, Tis estin houtos hos lalei blasphēmias</strong> — the scribes and Pharisees began to reason: who is this who speaks blasphemy? — <em>dialogizesthai</em> (to reason, deliberate — Luke uses this for internal, often hostile calculation, cf. 1:29; 2:35; 3:15) is internal, not voiced aloud; Jesus perceives it (v.22). The charge of blasphemy is the formal religious accusation: <em>blasphēmia</em> (defaming, reviling) of God — specifically, usurping divine prerogatives. <strong>tis dynatai hamartias aphienai ei mē monos ho theos</strong> — who can forgive sins except God alone? — this is the correct theological premise; the scribes\' error is not the premise but the failure to recognize who stands before them.</p>',
    "22": '<p><strong>epignous de ho Iēsous tous dialogismous autōn apokritheis eipen pros autous</strong> — Jesus, knowing their deliberations, answered and said to them — <em>epignous</em> (having known, perceived — aorist of <em>epiginōskō</em>, intensive knowing) indicates supernatural cognition of unexpressed thoughts, not inference from facial expressions. This is one of Luke\'s consistent demonstrations of Jesus\'s divine omniscience (cf. 6:8; 9:47; 11:17). <strong>ti dialogizesthe en tais kardiais hymōn</strong> — why are you deliberating in your hearts? — the internal reasoning is exposed and addressed directly; the question confronts rather than accuses.</p>',
    "23": '<p><strong>ti estin eukopōteron, eipein, Apheontai soi hai hamartiai sou, ē eipein, Egeire kai peripatei</strong> — which is easier: to say, your sins are forgiven, or to say, rise and walk? — the rhetorical question addresses what is easier to say, not to do. Pronouncing forgiveness is easier to say because it cannot be immediately verified; commanding physical healing is immediately verifiable and the healer is immediately accountable to the result. By performing the visible miracle, Jesus provides public verification of the invisible divine action (forgiveness) that no human can authenticate.</p>',
    "24": '<p><strong>hina de eidēte hoti ho huios tou anthrōpou exousian echei epi tēs gēs aphienai hamartias</strong> — but so that you may know that the Son of Man has authority on earth to forgive sins — <em>ho huios tou anthrōpou</em> (the Son of Man) is Jesus\'s characteristic self-designation in the Synoptics; in Dan 7:13-14 the Son of Man receives from the Ancient of Days universal authority, glory, and dominion. Jesus applies this Danielic title to the one who has <em>exousian ... epi tēs gēs</em> — authority on earth (not merely eschatological authority, but present, operative authority in the physical world). The healing that follows is the public demonstration of this claim.</p>',
    "25": '<p><strong>kai parachrēma anastas enōpion autōn aras eph ho kateiketo apēlthen eis ton oikon autou doxazōn ton theon</strong> — immediately he rose before them, took up what he had lain on, and went home glorifying God — <em>parachrēma</em> (immediately, at once — Luke\'s preferred term for instantaneous miraculous healing, cf. 1:64; 4:39; 8:44,47; 13:13; 18:43; Acts 3:7; 5:10) signals the completeness of divine power. The former paralytic carries his own stretcher — the instrument of his helplessness becomes the trophy of his healing. <em>Doxazōn ton theon</em> (glorifying God) is the proper response: the man attributes the healing to God, not merely to the healer.</p>',
    "26": '<p><strong>kai ekstasis elaben hapantas kai edoxazon ton theon</strong> — astonishment seized all and they were glorifying God — <em>ekstasis</em> (ecstasy, being outside oneself, displacement by overwhelming experience) is the strongest Greek term for stupefied amazement; the crowd is beyond ordinary response. <strong>kai eplēsthēsan phobou legontes hoti eidomen paradoxa sēmeron</strong> — they were filled with fear, saying: we have seen remarkable things today — <em>paradoxa</em> (wonderful things, paradoxes — things contrary to ordinary expectation) is a Lukan hapax; the crowd\'s assessment captures the epistemological shock of divine intrusion into the ordinary. <em>Sēmeron</em> (today) echoes 4:21 — the Jubilee-era of divine favor is the present moment of encounter with Jesus.</p>',
    "27": '<p><strong>kai meta tauta exēlthen kai etheasato telōnēn onomati Leuin kathēmenon epi to telōnion</strong> — after these things he went out and saw a tax collector named Levi sitting at the tax office — <em>telōnēs</em> (tax collector, toll collector) was a contracted collector for Rome, generally detested as both a collaborator and a notorious extortioner; <em>telōnion</em> (tax booth) is the collection point on a road or at a border. Levi (Matthew in Matt 9:9) sat at one of the Capernaum customs stations on the Via Maris trade route. <strong>kai eipen autō, Akolouthei moi</strong> — and he said to him: Follow me — the call is identical in form to Simon\'s (cf. v.10); no explanation, no preliminary discussion, one command.</p>',
    "28": '<p><strong>kai katalipōn panta anastas ēkolouthei autō</strong> — leaving everything, he rose and followed him — Levi\'s response is more total than Simon\'s in one respect: the tax collector abandoned a profitable licensed business with no possibility of return (a fishing boat can be reclaimed; a tax contract relinquished is gone). <em>Katalipōn panta</em> (having left everything) is Luke\'s emphatic phrase for complete discipleship abandonment (cf. 5:11; 18:28-29). The imperfect <em>ēkolouthei</em> (was following, began to follow) signals the ongoing nature of the following that begins here.</p>',
    "29": '<p><strong>kai epoiēsen dochēn megalēn Leuis autō en tē oikia autou</strong> — and Levi made a great banquet for him in his house — <em>dochē</em> (reception, banquet — a formal feast given in someone\'s honor) is a Lukan word (also 14:13); it signals a celebration of the call. <strong>kai ēn ochlos polys telōnōn kai allōn hoi ēsan met autōn katakeimenoi</strong> — there was a large crowd of tax collectors and others who were reclining with them — <em>katakeimai</em> (to recline at table) is the Greek dining posture for a formal meal. The gathering is Levi\'s professional network: tax collectors and the socially marginal ("others") who shared their stigma.</p>',
    "30": '<p><strong>kai egongyzon hoi Pharisaioi kai hoi grammateis autōn pros tous mathētas autou legontes</strong> — the Pharisees and their scribes murmured against his disciples saying — <em>egongyzon</em> (were murmuring, grumbling) is the LXX term for Israel\'s wilderness murmuring against Moses (Exod 15:24; 16:7-8; 17:3; Num 14:2,27; Ps 106:25); Luke\'s use of this exact word signals the Pharisees as recapitulating Israel\'s wilderness sin of complaining against God\'s appointed leader. <strong>Dia ti meta tōn telōnōn kai hamartoōlōn esthiete kai pinete</strong> — why do you eat and drink with tax collectors and sinners? — the table-fellowship challenge: eating with the <em>am ha-aretz</em> (people of the land) and tax collectors made a rabbi ritually suspect and socially compromised.</p>',
    "31": '<p><strong>kai apokritheis ho Iēsous eipen pros autous, Ou chreian echousin hoi hygiainontes iatrou alla hoi kakōs echontes</strong> — Jesus answered them: those who are well have no need of a physician, but those who are sick — the physician proverb is known from Greek sources (Plutarch, Diogenes Laertius) and is probably a common wisdom saying. Luke\'s ironic appropriateness: he is addressing the physician-metaphor to a physician\'s audience (Luke himself). <em>Hoi hygiainontes</em> (those who are well, healthy) vs. <em>hoi kakōs echontes</em> (those who are doing badly, having it badly = the sick) sets up the social analogy Jesus will make explicit in v.32.</p>',
    "32": '<p><strong>ouk elēlytha kalesai dikaious alla hamartōlous eis metanoian</strong> — I have not come to call the righteous, but sinners to repentance — <em>kalesai</em> (to call, summon) is the vocabulary of divine election and invitation; the same word is used for God\'s call of Abraham, Israel, and the prophets. <em>Dikaious</em> (righteous ones) is ironic: the Pharisees consider themselves righteous; Jesus does not contest their self-assessment but reframes the mission. <em>Hamartoōlous eis metanoian</em> — sinners to repentance — <em>metanoia</em> (change of mind, turning) is distinctively Lukan; it occurs more in Luke-Acts than in all other NT writings combined and is the defining characteristic of the kingdom\'s response requirement.</p>',
    "33": '<p><strong>hoi de eipen pros auton, Hoi mathētai Iōannou nēsteuousin pyknōs kai deēseis poioyntai</strong> — they said to him: John\'s disciples fast often and make prayers — <em>nēsteuousin pyknōs</em> (fast frequently, regularly) — the Pharisees (m. Taanit) fasted Mondays and Thursdays in addition to the mandatory Day of Atonement fast; John\'s ascetic movement fasted similarly. <em>Deēseis poiountai</em> (they make/perform prayers) — formal prayer as religious discipline. <strong>homoiōs kai hoi tōn Pharisaiōn, hoi de soi esthiousin kai pinousin</strong> — and likewise the Pharisees\', but yours eat and drink — the accusation is framed as a contrast between two recognized religious traditions (Johannine, Pharisaic) and Jesus\'s notably different practice.</p>',
    "34": '<p><strong>ho de Iēsous eipen pros autous, Mē dynasthe tous huious tou nymphōnos en hō ho numphios met autōn estin poiēsai nēsteusai</strong> — Jesus said to them: can you make the sons of the bridal chamber fast while the bridegroom is with them? — <em>huioi tou nymphōnos</em> (sons of the bridal chamber = wedding guests, groomsmen) is a Semitic idiom for those belonging to the bridal party. The <em>nymphios</em> (bridegroom) is a well-established image for YHWH in relationship to Israel (Isa 62:5; Jer 2:2; Hos 2:16-20; Ezek 16). Jesus applies the bridegroom image to himself without explanation; the audience would understand the implication: the messianic age has arrived, and fasting (mourning) is incompatible with the bridegroom\'s presence.</p>',
    "35": '<p><strong>eleusontai de hēmerai kai hotan aparthē ap autōn ho numphios</strong> — but days will come when the bridegroom is taken away from them — <em>aparthē</em> (is taken away, removed by force — aorist passive of <em>apairō</em>) is a passive that implies external force, not natural departure; this is a cryptic Passion reference, the first in Luke. The wedding-feast of the messianic era will be interrupted by the violent removal of the bridegroom — an event only later identified explicitly as the crucifixion. <strong>tote nēsteusousin en ekeinais tais hēmerais</strong> — then they will fast in those days — fasting in the post-Easter era is legitimate, but as grief for the absent bridegroom, not as religious performance.</p>',
    "36": '<p><strong>elegen de kai parabolēn pros autous</strong> — he was also telling a parable to them — the two parables of incompatible structures address the deeper question behind the fasting-debate: the new era is qualitatively incompatible with the old order, not merely quantitatively different. <strong>Oudeis epilamma schismas apo himatiou kainou epiballei epi himation palaion</strong> — no one tears a patch from a new garment and sews it on an old garment — the garment parable: the new garment is destroyed to patch the old, and the patch from the new does not match the old anyway (shrinkage difference). The new era cannot be used as a resource to repair the old religious order; it would ruin both.</p>',
    "37": '<p><strong>kai oudeis ballei oinon neon eis askous palaious</strong> — and no one puts new wine into old wineskins — <em>askous</em> (wineskins, leather bags made from goatskin) were used for wine storage; old skins had already been stretched to their limit by previous fermentation. New wine (<em>oinos neos</em>) continues to ferment and expand; old skins cannot accommodate the expansion and burst. <strong>ei de mē ge, rēxei ho oinos ho neos tous askous</strong> — otherwise the new wine will burst the wineskins — the structural incompatibility is not a judgment on the old but a statement of physical necessity. The new era of the Spirit is not compatible with the containing structures of Second Temple Judaism\'s religious economy.</p>',
    "38": '<p><strong>alla oinon neon eis askous kainous blēteon</strong> — but new wine must be put into new wineskins — <em>kainous</em> (new in quality, fresh, unused — vs. <em>neos</em> which is new in time) is Luke\'s word for the eschatologically new. The <em>dei</em>-equivalent <em>blēteon</em> (must be put, verbal adjective of necessity) makes this a structural requirement, not a preference. The new covenant community, the church that Luke will narrate in Acts, is the new wineskin adequate to contain the Spirit\'s new wine. The parable does not deprecate the old but insists on structural correspondence between content and container.</p>',
    "39": '<p><strong>kai oudeis piōn palaion thelei neon, legei gar ho palaios chrēstos estin</strong> — and no one after drinking old wine desires new, for they say: the old is good — this final saying is Luke\'s addition (absent from Matthew and Mark) and is often read as ironic comment on the Pharisees\' preference for the old order. <em>Chrēstos</em> (good, pleasant, well-suited, palatable) is the vocabulary of practical usefulness rather than moral excellence. The person habituated to the old wine of Second Temple piety does not feel a deficit; the palatability of the familiar obscures the need for the new. Luke presents this as an explanation of why the religious establishment resists Jesus\'s new era — not malice but acquired taste.</p>',
  }
}

